  ('bookkeeper-moex-01362', 'bookkeeper', 'bookkeeper-moex-103-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '甲公司發行面額$10之普通股，流通在外200,000股，另外亦發行面額$100，6%之累積特別股10,000股。 過去三年及今年皆未發放股利，若公司本年度欲宣告發放$150,000 之股利，則今年底分配給特別股之股 利是多少？', '["$150,000", "$240,000", "$360,000", "$480,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:27+00:00", "source_pdf_sha1": "eb7c2b3095ad", "answer_pdf_sha1": "151da49cfd80", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "602", "s": "1302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
