  ('bookkeeper-moex-01367', 'bookkeeper', 'bookkeeper-moex-103-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '甲公司於X3年1月1日發行三年期，票面利率10%，面額$400,000之公司債，於每年6月30日及 12月31日各付息一次，公司債發行價格為$435,000，有效利率為8%。該公司採有效利率法攤銷折、 溢價。則X3年之利息費用為：', '["$34,696", "$34,800", "$40,000", "$43,500"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:27+00:00", "source_pdf_sha1": "eb7c2b3095ad", "answer_pdf_sha1": "151da49cfd80", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "602", "s": "1302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
